#include "XSbench_header.cuh"
#include <thrust/sort.h>
#include <thrust/device_ptr.h>
#include <thrust/host_vector.h>
#include <thrust/sequence.h>
#include <thrust/execution_policy.h>
#include <thrust/functional.h>
#include <thrust/copy.h>
#include <thrust/iterator/zip_iterator.h>
#include <thrust/tuple.h>

unsigned long long run_event_based_simulation_optimization_1(Inputs in, SimulationData GSD, int mype)
{
    char *optimization_name = (char *)"Optimization 1 - Kernel splitting + full material & energy sort";

    if (mype == 0)
        printf("Simulation Kernel:\"%s\"\n", optimization_name);

    if (mype == 0)
        printf("Allocating additional data required by optimized kernel...\n");

    size_t sz;
    size_t total_sz = 0;
    double start, stop;

    sz = in.lookups * sizeof(double);
    cudaMallocHost(&GSD.p_energy_samples, sz);
    total_sz += sz;
    GSD.length_p_energy_samples = in.lookups;

    sz = in.lookups * sizeof(int);
    cudaMallocHost(&GSD.mat_samples, sz);
    total_sz += sz;
    GSD.length_mat_samples = in.lookups;

    if (mype == 0)
        printf("Allocated an additional %.0lf MB of host pinned memory.\n", total_sz / 1024.0 / 1024.0);

    // Sampling kernel
    const int threads_per_block = 256;
    int blocks = (in.lookups + threads_per_block - 1) / threads_per_block;

    sampling_kernel<<<blocks, threads_per_block>>>(in, GSD);
    gpuErrchk(cudaPeekAtLastError());
    gpuErrchk(cudaDeviceSynchronize());

    if (mype == 0)
        printf("finished sampling...\n");

    start = get_time();

    // Sort by material, then energy
    thrust::device_vector<int> d_mat_samples(in.lookups);
    thrust::device_vector<double> d_p_energy_samples(in.lookups);

    gpuErrchk(cudaMemcpy(thrust::raw_pointer_cast(d_mat_samples.data()), GSD.mat_samples, in.lookups * sizeof(int), cudaMemcpyHostToDevice));
    gpuErrchk(cudaMemcpy(thrust::raw_pointer_cast(d_p_energy_samples.data()), GSD.p_energy_samples, in.lookups * sizeof(double), cudaMemcpyHostToDevice));

    // Sort by mat_samples ascending, then p_energy_samples ascending
    auto zipped_begin = thrust::make_zip_iterator(thrust::make_tuple(d_mat_samples.begin(), d_p_energy_samples.begin()));
    auto zipped_end = thrust::make_zip_iterator(thrust::make_tuple(d_mat_samples.end(), d_p_energy_samples.end()));

    thrust::sort(zipped_begin, zipped_end, 
        [] __device__ (const thrust::tuple<int, double>& a, const thrust::tuple<int, double>& b) {
            if (thrust::get<0>(a) < thrust::get<0>(b)) return true;
            if (thrust::get<0>(a) > thrust::get<0>(b)) return false;
            return thrust::get<1>(a) < thrust::get<1>(b);
        });

    gpuErrchk(cudaMemcpy(GSD.mat_samples, thrust::raw_pointer_cast(d_mat_samples.data()), in.lookups * sizeof(int), cudaMemcpyDeviceToHost));
    gpuErrchk(cudaMemcpy(GSD.p_energy_samples, thrust::raw_pointer_cast(d_p_energy_samples.data()), in.lookups * sizeof(double), cudaMemcpyDeviceToHost));

    stop = get_time();

    if (mype == 0)
        printf("Material and energy sort took %.3lf seconds\n", stop - start);

    // Count samples per material and offsets
    start = stop;

    int num_samples_per_mat[12] = {0};
    for (int l = 0; l < in.lookups; l++)
        num_samples_per_mat[GSD.mat_samples[l]]++;

    int offsets[12] = {0};
    for (int m = 1; m < 12; m++)
        offsets[m] = offsets[m - 1] + num_samples_per_mat[m - 1];

    stop = get_time();
    if (mype == 0)
        printf("Counting samples and offsets took %.3lf seconds\n", stop - start);
    start = stop;

    // Now sort energies within each material segment
    for (int m = 0; m < 12; m++)
    {
        if (num_samples_per_mat[m] > 1)
        {
            thrust::device_ptr<double> energies_dev = thrust::device_pointer_cast(GSD.p_energy_samples + offsets[m]);
            thrust::device_ptr<int> mats_dev = thrust::device_pointer_cast(GSD.mat_samples + offsets[m]);

            // Copy to device
            gpuErrchk(cudaMemcpy(energies_dev.get(), GSD.p_energy_samples + offsets[m], num_samples_per_mat[m] * sizeof(double), cudaMemcpyHostToDevice));
            gpuErrchk(cudaMemcpy(mats_dev.get(), GSD.mat_samples + offsets[m], num_samples_per_mat[m] * sizeof(int), cudaMemcpyHostToDevice));

            thrust::sort_by_key(energies_dev, energies_dev + num_samples_per_mat[m], mats_dev);

            // Copy back to host
            gpuErrchk(cudaMemcpy(GSD.p_energy_samples + offsets[m], energies_dev.get(), num_samples_per_mat[m] * sizeof(double), cudaMemcpyDeviceToHost));
            gpuErrchk(cudaMemcpy(GSD.mat_samples + offsets[m], mats_dev.get(), num_samples_per_mat[m] * sizeof(int), cudaMemcpyDeviceToHost));
        }
    }

    stop = get_time();
    if (mype == 0)
        printf("Energy Sorts took %.3lf seconds\n", stop - start);

    start = get_time();

    unsigned long long verification = 0;

    // Allocate verification array on device
    unsigned long *d_verification;
    gpuErrchk(cudaMalloc(&d_verification, in.lookups * sizeof(unsigned long)));
    gpuErrchk(cudaMemset(d_verification, 0, in.lookups * sizeof(unsigned long)));

    // Copy samples to device
    double *d_p_energy_samples;
    int *d_mat_samples;
    gpuErrchk(cudaMalloc(&d_p_energy_samples, in.lookups * sizeof(double)));
    gpuErrchk(cudaMalloc(&d_mat_samples, in.lookups * sizeof(int)));

    gpuErrchk(cudaMemcpy(d_p_energy_samples, GSD.p_energy_samples, in.lookups * sizeof(double), cudaMemcpyHostToDevice));
    gpuErrchk(cudaMemcpy(d_mat_samples, GSD.mat_samples, in.lookups * sizeof(int), cudaMemcpyHostToDevice));

    int offset = 0;
    for (int m = 0; m < 12; m++)
    {
        int n_samples = num_samples_per_mat[m];
        if (n_samples == 0) continue;

        int blocks = (n_samples + threads_per_block - 1) / threads_per_block;
        xs_lookup_kernel_optimization_1<<<blocks, threads_per_block>>>(in, GSD, m, offset, d_p_energy_samples, d_mat_samples, d_verification);
        gpuErrchk(cudaPeekAtLastError());
        gpuErrchk(cudaDeviceSynchronize());

        offset += n_samples;
    }

    // Copy verification results back
    unsigned long *h_verification = (unsigned long *)malloc(in.lookups * sizeof(unsigned long));
    gpuErrchk(cudaMemcpy(h_verification, d_verification, in.lookups * sizeof(unsigned long), cudaMemcpyDeviceToHost));
    for (int i = 0; i < in.lookups; i++) {
        verification += h_verification[i];
    }
    free(h_verification);

    gpuErrchk(cudaFree(d_verification));
    gpuErrchk(cudaFree(d_p_energy_samples));
    gpuErrchk(cudaFree(d_mat_samples));

    stop = get_time();
    if (mype == 0)
        printf("XS Lookups took %.3lf seconds\n", stop - start);

    cudaFreeHost(GSD.p_energy_samples);
    cudaFreeHost(GSD.mat_samples);
    GSD.p_energy_samples = nullptr;
    GSD.mat_samples = nullptr;

    return verification;
}

__global__ void sampling_kernel(Inputs in, SimulationData GSD)
{
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i >= in.lookups) return;

    uint64_t seed = STARTING_SEED;
    seed = fast_forward_LCG(seed, 2ULL * i);

    double p_energy = LCG_random_double(&seed);
    int mat = pick_mat(&seed);

    GSD.p_energy_samples[i] = p_energy;
    GSD.mat_samples[i] = mat;
}

__global__ void xs_lookup_kernel_optimization_1(Inputs in, SimulationData GSD, int mat, int offset, double *d_p_energy_samples, int *d_mat_samples, unsigned long *d_verification)
{
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    int idx = offset + i;
    if (i >= in.lookups) return;

    if (d_mat_samples[idx] != mat) return;

    double p_energy = d_p_energy_samples[idx];
    int mat_sample = d_mat_samples[idx];

    double macro_xs_vector[5] = {0};

    calculate_macro_xs(
        p_energy,
        mat_sample,
        in.n_isotopes,
        in.n_gridpoints,
        GSD.num_nucs,
        GSD.concs,
        GSD.unionized_energy_array,
        GSD.index_grid,
        GSD.nuclide_grid,
        GSD.mats,
        macro_xs_vector,
        in.grid_type,
        in.hash_bins,
        GSD.max_num_nucs
    );

    double max_val = -1.0;
    int max_idx = 0;
    for (int j = 0; j < 5; j++) {
        if (macro_xs_vector[j] > max_val) {
            max_val = macro_xs_vector[j];
            max_idx = j;
        }
    }

    atomicAdd(&d_verification[idx], (unsigned long)(max_idx + 1));
}
